import type {
  AudioInputDeviceInfo,
  AuthState,
  DesktopSettings,
  DictationSessionEvent,
  IpcResponse,
  MainWindowStateEvent,
  SignInPayload,
  SignUpPayload,
  StateChangeEvent,
  SyncStatusEvent,
  TranscriptionUpdateEvent,
} from 'dictapilot-desktop-shared';

interface DictationAPI {
  startDictation: () => Promise<IpcResponse<DictationSessionEvent>>;
  stopDictation: () => Promise<IpcResponse>;
  updateSettings: (settings: Record<string, string>) => Promise<IpcResponse<DesktopSettings>>;
  getSettings: () => Promise<IpcResponse<DesktopSettings>>;
  getHistory: () => Promise<IpcResponse<any[]>>;
  getAudioInputDevices: (requestPermission?: boolean) => Promise<IpcResponse<AudioInputDeviceInfo[]>>;
  getSelectedAudioInput: () => Promise<IpcResponse<string>>;
  setSelectedAudioInput: (deviceId: string) => Promise<IpcResponse<string>>;
  signUp: (payload: SignUpPayload) => Promise<IpcResponse<AuthState>>;
  signIn: (payload: SignInPayload) => Promise<IpcResponse<AuthState>>;
  signInWithGoogle: () => Promise<IpcResponse<AuthState>>;
  signOut: () => Promise<IpcResponse<AuthState>>;
  getAuthState: () => Promise<IpcResponse<AuthState>>;
  updateSyncPreferences: (payload: { enabled: boolean }) => Promise<IpcResponse<AuthState>>;
  getMainWindowState: () => Promise<IpcResponse<MainWindowStateEvent>>;
  minimizeMainWindow: () => Promise<IpcResponse>;
  toggleMainWindowMaximize: () => Promise<IpcResponse>;
  closeMainWindow: () => Promise<IpcResponse>;
  closeWidgetWindow: () => Promise<IpcResponse>;
  sendAudioData: (sessionId: string, buffer: ArrayBuffer) => void;
  onAmplitudeUpdate: (callback: (amp: number) => void) => () => void;
  onTranscriptionUpdate: (callback: (data: TranscriptionUpdateEvent) => void) => () => void;
  onStateChange: (callback: (data: StateChangeEvent) => void) => () => void;
  onHotkeyPress: (callback: () => void) => () => void;
  onAuthStateChange: (callback: (data: AuthState) => void) => () => void;
  onSyncStatusChange: (callback: (data: SyncStatusEvent) => void) => () => void;
  onMainWindowStateChange: (callback: (data: MainWindowStateEvent) => void) => () => void;
  onAudioDevicesChanged: (callback: () => void) => () => void;
}

declare global {
  interface Window {
    dictationAPI: DictationAPI;
  }
}

export {};
